@app.route('/api/admin/qa-seed', methods=['POST'])
def admin_qa_seed():
    """Synthetic session seeder für Browser-QA. Dormant bis env gesetzt.

    Body: {"scenario": "needs_review" | "done"}
    Header: X-QA-Seed-Token: <muss zu env AEROTAX_QA_SEED_TOKEN matchen>

    Returns: {token, short_code, canonical_state, pdf_allowed, download_url, expires_at}
    """
    expected = os.environ.get('AEROTAX_QA_SEED_TOKEN', '').strip()
    if not expected:
        return jsonify({
            'error': 'qa-seed endpoint dormant',
            'hint':  'set env AEROTAX_QA_SEED_TOKEN to enable',
        }), 403
    provided = (request.headers.get('X-QA-Seed-Token') or '').strip()
    if not provided or not hmac.compare_digest(expected, provided):
        return jsonify({'error': 'Unauthorized'}), 401

    body = request.get_json(silent=True) or {}
    scenario = (body.get('scenario') or '').strip().lower()
    if scenario not in ('needs_review', 'done'):
        return jsonify({'error': "scenario must be 'needs_review' or 'done'"}), 400

    job_id = str(uuid.uuid4())
    result_data = dict(_QA_SEED_RESULT_TEMPLATE)
    result_data['datum'] = datetime.now().strftime('%d.%m.%Y')

    if scenario == 'needs_review':
        result_data['_review_items'] = _build_qa_seed_review_items()
        download_url = None
    else:  # done
        result_data['_review_items'] = []
        try:
            pdf_bytes = erstelle_pdf(result_data)
            pdf_token = str(uuid.uuid4())
            _save_pdf(pdf_token, pdf_bytes, 'AeroTax_QA_Seed_2025.pdf', hours=24)
            download_url = f'/api/download/{pdf_token}'
        except Exception as e:
            print(f"[qa-seed] PDF generation failed: {e}")
            return jsonify({'error': f'pdf generation failed: {e}'}), 500

    token = _make_session_token(job_id)

    job_entry = {
        'job_id':         job_id,
        'status':         'done',
        'data':           result_data,
        'session_token':  token,
        'created_at':     datetime.utcnow().isoformat() + 'Z',
        'updated_at':     datetime.utcnow().isoformat() + 'Z',
        '_qa_seed':       True,
    }
    with _jobs_lock:
        _jobs[job_id] = job_entry
    _save_job_to_disk(job_id)

    _save_session(token, {
        'job_id':       job_id,
        'result_data':  result_data,
        'notes':        [],
        'download_url': download_url,
        'chat_history': [],
    })

    state = _classify_job_state(job_entry, None)
    expires_at = (datetime.utcnow() + timedelta(hours=SESSION_HOURS)).isoformat() + 'Z'

    print(f"[qa-seed] scenario={scenario} token={token[:12]}... job_id={job_id[:8]} "
          f"canonical={state['canonical_state']} pdf_allowed={state['pdf_allowed']}")

    return jsonify({
        'token':            token,
        'short_code':       _make_short_code(token),
        'job_id':           job_id,
        'scenario':         scenario,
        'canonical_state':  state['canonical_state'],
        'pdf_allowed':      state['pdf_allowed'],
        'download_url':     download_url,
        'expires_at':       expires_at,
        'note':             'QA test session — synthetic data, no Sonnet, no real customer PDF',
    }), 201


@app.route('/api/qa/<qid>/upvote', methods=['POST'])
def qa_upvote(qid):
    """Upvote für Frage oder Antwort. Body: {answer_id?}."""
    ip = request.headers.get('X-Forwarded-For', request.remote_addr or 'unknown').split(',')[0].strip()
    if not _qa_rate_check(ip, 'upvote', max_per_hour=60):
        return jsonify({'error': 'Zu viele Upvotes — bitte warte'}), 429
    body = request.get_json(silent=True) or {}
    answer_id = body.get('answer_id')
    ip_hash = _hashlib.sha256((ip + _recovery_pepper()).encode()).hexdigest()[:8]
    target_type = 'answer' if answer_id else 'question'
    target_id = answer_id if answer_id else qid

    if SB_AVAILABLE:
        try:
            # Minimaler Spam-Schutz: 1-Sekunden-Window — User kann frei mehrfach liken
            cutoff = (datetime.utcnow() - timedelta(seconds=1)).isoformat()
            check = sb.table('upvotes').select('id').eq('target_type', target_type).eq('target_id', target_id).eq('ip_hash', ip_hash).gte('created_at', cutoff).limit(1).execute()
            if check.data:
                return jsonify({'error': 'Bitte langsamer klicken'}), 429
            # Alte Votes derselben IP fürs selbe Target löschen (>1s alt) — UNIQUE-Constraint Workaround
            try:
                sb.table('upvotes').delete().eq('target_type', target_type).eq('target_id', target_id).eq('ip_hash', ip_hash).lt('created_at', cutoff).execute()
            except Exception as _de:
                print(f"[supabase] cleanup old votes fail: {_de}")
            sb.table('upvotes').insert({
                'target_type': target_type,
                'target_id': target_id,
                'ip_hash': ip_hash,
            }).execute()
            # Counts zurückgeben
            cutoff_30d = (datetime.utcnow() - timedelta(days=30)).isoformat()
            r30 = sb.table('upvotes').select('id', count='exact').eq('target_type', target_type).eq('target_id', target_id).gte('created_at', cutoff_30d).execute()
            rtotal = sb.table('upvotes').select('id', count='exact').eq('target_type', target_type).eq('target_id', target_id).execute()
            return jsonify({
                'ok': True,
                'upvotes_30d': r30.count or 0,
                'upvotes_total': rtotal.count or 0,
            })
        except Exception as e:
            err_str = str(e).lower()
            if 'unique' in err_str or 'duplicate' in err_str:
                return jsonify({'error': 'Schon gevotet — bitte 1 Stunde warten'}), 429
            print(f"[supabase] upvote fail: {e}")
            return jsonify({'error': 'Speichern fehlgeschlagen'}), 500

    # Disk-Fallback
    vote = {'ts': datetime.utcnow().isoformat() + 'Z', 'h': ip_hash}
    with _qa_lock:
        questions = _qa_load()
        for q in questions:
            if q['id'] == qid:
                target = None
                if answer_id:
                    for a in q.get('answers', []):
                        if a['id'] == answer_id:
                            target = a; break
                else:
                    target = q
                if not target:
                    return jsonify({'error': 'Antwort nicht gefunden'}), 404
                target.setdefault('upvotes_log', [])
                cutoff = datetime.utcnow() - timedelta(seconds=1)
                already_voted = any(
                    v.get('h') == ip_hash and datetime.fromisoformat(v.get('ts','').replace('Z','')) >= cutoff
                    for v in target['upvotes_log']
                )
                if already_voted:
                    return jsonify({'error': 'Bitte langsamer klicken'}), 429
                target['upvotes_log'].append(vote)
                _qa_save(questions)
                return jsonify({
                    'ok': True,
                    'upvotes_30d': _qa_effective_upvotes(target['upvotes_log']),
                    'upvotes_total': _qa_total_upvotes(target['upvotes_log']),
                })
    return jsonify({'error': 'Nicht gefunden'}), 404


