def _bytes_list(file_list):
    """Normalisiert eine Liste aus reinen bytes ODER (bytes, filename) Tupeln → Liste von bytes."""
    result = []
    for item in (file_list or []):
        if isinstance(item, tuple):
            result.append(item[0])
        else:
            result.append(item)
    return result

def _bytes_filename_list(file_list):
    """Normalisiert → Liste von (bytes, filename) Tupeln."""
    result = []
    for item in (file_list or []):
        if isinstance(item, tuple):
            result.append(item)
        else:
            result.append((item, ''))
    return result


# ════════════════════════════════════════════════════════════════════════════
# v11 Clean-Release Phase 1 — Document Type Detection final.
#
# Klassifiziert eine hochgeladene PDF in eine der 5 finalen Kategorien:
#   - lohnsteuerbescheinigung
#   - streckeneinsatz
#   - dienstplan_cas
#   - legacy_ignored_flight_hours_summary
#   - unknown
#
# Heuristik basiert auf Text-Markers + Dateinamen-Patterns. Wenn pdfplumber
# fehlschlaegt: Filename-only. Wenn beides leer: 'unknown'.
# ════════════════════════════════════════════════════════════════════════════

DOC_TYPE_LSB         = 'lohnsteuerbescheinigung'
DOC_TYPE_SE          = 'streckeneinsatz'
DOC_TYPE_CAS         = 'dienstplan_cas'
DOC_TYPE_LEGACY_FLUG = 'legacy_ignored_flight_hours_summary'
DOC_TYPE_UNKNOWN     = 'unknown'

DOC_TYPES_ALL = (
    DOC_TYPE_LSB, DOC_TYPE_SE, DOC_TYPE_CAS,
    DOC_TYPE_LEGACY_FLUG, DOC_TYPE_UNKNOWN,
)


def classify_uploaded_pdf_doc_type(pdf_bytes, filename=''):
    """v11 Clean-Release: heuristische Doc-Typ-Erkennung fuer hochgeladene PDFs.

    Args:
        pdf_bytes: Roh-Bytes der PDF (oder leerer Wert).
        filename:  Dateiname (case-insensitive, optional).

    Returns:
        Einer aus DOC_TYPES_ALL.

    Regeln (Priorisierung):
        1. Filename-Pattern PUB_/NTF_ → dienstplan_cas.
        2. Filename enthaelt "Flugstunden" / "Stundenuebersicht" → legacy_ignored_flight_hours_summary
           (egal was im Text steht — Filename ist eindeutig).
        3. Inhalt: "Lohnsteuerbescheinigung" / "Steueridentifikationsnummer" → lohnsteuerbescheinigung.
        4. Inhalt: "Streckeneinsatz" / "Einsatzabrechnung" + "stfrei" → streckeneinsatz.
        5. Inhalt: "Flugstundenuebersicht" / "FLUGSTUNDEN-UEBERSICHT" → legacy_ignored_flight_hours_summary.
        6. Inhalt: "Briefingzeit" / "LH<num>" + Routing + Uhrzeiten → dienstplan_cas.
        7. Sonst: unknown.
    """
    fname_lower = (filename or '').lower()

    # 1. Filename-only fuer CAS (PUB_/NTF_-Dateien)
    if re.match(r'^(pub|ntf)_\d+', fname_lower):
        return DOC_TYPE_CAS

    # 2. Filename-only fuer Flugstundenuebersicht
    if 'flugstunden' in fname_lower or 'stundenuebersicht' in fname_lower or 'stunden-uebersicht' in fname_lower:
        return DOC_TYPE_LEGACY_FLUG

    # Text-Extraktion (falls moeglich)
    text = ''
    if pdf_bytes:
        try:
            import pdfplumber, io
            with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
                # Nur die ersten 3 Seiten — genug fuer Header/Titel
                for page in pdf.pages[:3]:
                    text += (page.extract_text() or '') + '\n'
        except Exception:
            text = ''

    text_low = text.lower()

    # 3. LSB
    if 'lohnsteuerbescheinigung' in text_low or 'steueridentifikationsnummer' in text_low:
        return DOC_TYPE_LSB

    # 4. SE — "Streckeneinsatz" + Spesen-Pattern
    if 'streckeneinsatz' in text_low or 'einsatzabrechnung' in text_low:
        # Bestaetigung durch Spesen-Marker
        if 'stfrei' in text_low or 'pauschal' in text_low or 'verpflegung' in text_low:
            return DOC_TYPE_SE
        return DOC_TYPE_SE  # Header allein genuegt

    # 5. Flugstundenuebersicht (Content-basiert)
    if 'flugstunden-übersicht' in text_low or 'flugstundenübersicht' in text_low \
       or 'flugstunden-uebersicht' in text_low or 'flugstundenuebersicht' in text_low \
       or 'flugstunden' in text_low and 'fl strecken' in text_low:
        return DOC_TYPE_LEGACY_FLUG

    # 6. CAS-Dienstplan (Content-basiert)
    if 'briefingzeit' in text_low:
        return DOC_TYPE_CAS
    # LH-Flugnummer + Uhrzeit + Routing (Dienstplan-Detail)
    if re.search(r'lh\s?\d{2,4}\b', text_low) and re.search(r'\d{2}:\d{2}', text):
        if 'roster' in text_low or 'dienstplan' in text_low or 'pub_' in text_low:
            return DOC_TYPE_CAS

    return DOC_TYPE_UNKNOWN


def _lsb_extract_via_regex(text):
    """Liefert numerische Werte direkt aus dem PDF-Text via Regex.
    Nullwerte = nicht gefunden / Format unbekannt."""
    def find(pattern, default=0.0):
        m = re.search(pattern, text, re.IGNORECASE | re.DOTALL)
        if m:
            try: return float(m.group(1).replace('.','').replace(',','.'))
            except: pass
        return default

    out = {}
    # Brutto: mehrere Patterns für Format-Robustheit
    b = find(r'Bruttoarbeitslohn[^\d]+([\d\.]+,\d{2})')
    if b == 0: b = find(r'3\.\s*Bruttoarbeitslohn\s+([\d\.]+,\d{2})')
    if b == 0: b = find(r'Bruttoarbeitslohn[\s\S]{0,200}?(\d{2,6}[\.,]\d{2})')
    if b == 0: b = find(r'Arbeitslohn[^\d]+(\d{2,6}[\.,]\d{2})')
    out['brutto'] = b
    out['lohnsteuer'] = find(r'Lohnsteuer von 3\.[^\d]+([\d\.]+,\d{2})')
    out['soli']       = find(r'Solidarit[^\d]+([\d\.]+,\d{2})')
    out['kirchensteuer_an'] = find(r'Kirchensteuer des\nArbeitnehmers von 3\.[^\d]+([\d\.]+,\d{2})')
    out['ag_fahrt_z17']     = find(r'Entfernungspauschale anzurechnen sind\s+([\d\.]+,\d{2})')
    out['ag_fahrt_z18_pauschal'] = find(r'15%[^\d]+([\d\.]+,\d{2})')
    rv_ag = find(r'22\.\s+Arbeitgeber[^\n]+\nJahreshinzurechnungsbetrag versicherung\s+([\d\.]+,\d{2})')
    if rv_ag == 0:
        rv_ag = find(r'22\.\s+Arbeitgeber[^\d\n]+\n[^\d\n]+\s+([\d\.]+,\d{2})')
    out['rv_ag'] = rv_ag
    out['rv_an'] = find(r'23\.\s+Arbeitnehmer[^\d]+Renten-?\n\s*versicherung\s+([\d\.]+,\d{2})')
    out['kv_an'] = find(r'25\.\s+Arbeitnehmerbeitr[^\d]+Kranken-?\n\s*versicherung\s+([\d\.]+,\d{2})')
    out['pv_an'] = find(r'26\.\s+Arbeitnehmerbeitr[^\d]+Pflege-?\n\s*versicherung\s+([\d\.]+,\d{2})')
    out['av_an'] = find(r'27\.\s+Arbeitnehmerbeitr[^\d]+Arbeitslosenver-?\n?\s*sicherung\s+([\d\.]+,\d{2})')
    out['verpflegungszuschuss_z20'] = find(r'Verpflegungszusch[^\d]+([\d\.]+,\d{2})')
    out['doppelhaus_z21']           = find(r'doppelter Haushalt[^\d]+([\d\.]+,\d{2})')
    return out


def _lsb_extract_via_claude(text, regex_hints=None, label='lsb-extract', extra_instruction=None):
    """Liefert die numerischen Felder via Claude. Wird IMMER aufgerufen
    (KI ist Source of Truth, Regex nur Cross-Check). Bei Diskrepanz mit
    regex_hints wird ein Re-Check ausgelöst.
    extra_instruction: optionaler zusätzlicher Anweisungsblock (z.B. Diskrepanz-Resolution)."""
    if not ANTHROPIC_KEY or not text:
        if not ANTHROPIC_KEY:
            print(f"[LSB-parser/{label}] ANTHROPIC_KEY fehlt → fallback auf Regex-only")
        return {}
    fields = ['brutto','lohnsteuer','soli','kirchensteuer_an','ag_fahrt_z17',
              'ag_fahrt_z18_pauschal','rv_ag','rv_an','kv_an','pv_an','av_an',
              'verpflegungszuschuss_z20','doppelhaus_z21']
    hint_block = ''
    if regex_hints:
        hint_lines = '\n'.join(f'  {k}: {v}' for k, v in regex_hints.items() if v)
        if hint_lines:
            hint_block = ('\nRegex-Vorschläge (zur Plausi-Prüfung — können falsch sein):\n'
                          + hint_lines + '\n')
    extra_block = f'\n{extra_instruction}\n' if extra_instruction else ''
    prompt = (
        "Du bekommst den Text einer deutschen Lohnsteuerbescheinigung. "
        "Lies sorgfältig und extrahiere die Beträge — gib NUR ein JSON-Objekt zurück, kein Erklärtext.\n\n"
        "Felder (alle in EUR als Zahl, 0 wenn nicht vorhanden):\n"
        '{\n'
        '  "brutto": <Bruttoarbeitslohn Zeile 3>,\n'
        '  "lohnsteuer": <einbehaltene Lohnsteuer Zeile 4>,\n'
        '  "soli": <Solidaritätszuschlag Zeile 5>,\n'
        '  "kirchensteuer_an": <Kirchensteuer AN Zeile 6/7>,\n'
        '  "ag_fahrt_z17": <Entfernungspauschale anzurechnen Zeile 17>,\n'
        '  "ag_fahrt_z18_pauschal": <15% pauschal Zeile 18>,\n'
        '  "rv_ag": <Arbeitgeber-RV Zeile 22a>,\n'
        '  "rv_an": <Arbeitnehmer-RV Zeile 23a>,\n'
        '  "kv_an": <KV-Arbeitnehmer Zeile 25>,\n'
        '  "pv_an": <PV-Arbeitnehmer Zeile 26>,\n'
        '  "av_an": <AV-Arbeitnehmer Zeile 27>,\n'
        '  "verpflegungszuschuss_z20": <stfrei Verpflegung Zeile 20>,\n'
        '  "doppelhaus_z21": <doppelter Haushalt Zeile 21>\n'
        '}\n'
        + hint_block + extra_block +
        "\nWichtig: deutsche Zahlen (1.234,56 = 1234.56 in JSON). Niemals Felder weglassen.\n\n"
        "PDF-Text:\n" + text[:10000]
    )
    try:
        client = anthropic.Anthropic(api_key=ANTHROPIC_KEY, timeout=180.0)
        resp = _claude_with_retry(client, 'claude-sonnet-4-5', 1500,
                                  [{'type': 'text', 'text': prompt}], label=label)
        ai_text = resp.content[0].text.strip()
        m = re.search(r'\{[\s\S]*\}', ai_text)
        if not m:
            print(f"[LSB-parser/{label}] kein JSON in Claude-Antwort: {ai_text[:200]}")
            return {}
        import json as _json
        data = _json.loads(m.group(0))
        out = {}
        for k in fields:
            v = data.get(k, 0)
            try: out[k] = float(v) if v else 0
            except: out[k] = 0
        return out
    except Exception as e:
        print(f"[LSB-parser/{label}] Claude fail: {e}")
        return {}


def parse_lohnsteuerbescheinigung(pdf_bytes_list):
    """
    Extrahiert ALLE steuerrelevanten Felder.
    Strategie: Regex (schnell) + Claude (immer) + Diskrepanz-Re-Check.
    KI ist Source of Truth — Regex nur Cross-Check + Notnagel bei API-Ausfall.
    """
    pdf_bytes_list = _bytes_list(pdf_bytes_list)
    result = {
        'brutto': 0, 'lohnsteuer': 0, 'soli': 0,
        'kirchensteuer_an': 0, 'kirchensteuer_eg': 0,
        'ag_fahrt_z17': 0, 'ag_fahrt_z18_pauschal': 0,
        'rv_an': 0, 'kv_an': 0, 'pv_an': 0, 'av_an': 0,
        'rv_ag': 0,
        'verpflegungszuschuss_z20': 0, 'doppelhaus_z21': 0,
        'identnr': '', 'geburtsdatum': '', 'personalnummer': '',
        'steuerklasse': '1', 'kinderfreibetraege': 0.0,
        'kirchensteuermerkmale': '',
        'arbeitgeber': 'Deutsche Lufthansa AG',
        'finanzamt': '', 'steuernummer_ag': '',
        'vorsorge_gesamt_an': 0,
        'rv_gesamt': 0,
    }

    for pdf_bytes in pdf_bytes_list:
        try:
            with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
                text = '\n'.join(p.extract_text() or '' for p in pdf.pages)

            print(f"[LSB-parser] PDF text len={len(text)}, head={text[:200].replace(chr(10),' | ')!r}")

            # ── 1) Regex-Extraktion (schnell, deterministisch) ──
            regex_vals = _lsb_extract_via_regex(text)
            print(f"[LSB-parser] Regex: brutto={regex_vals.get('brutto',0):.2f} "
                  f"z17={regex_vals.get('ag_fahrt_z17',0):.2f} "
                  f"lohnsteuer={regex_vals.get('lohnsteuer',0):.2f}")

            # ── 2) Claude-Extraktion (immer — Source of Truth) ──
            ai_vals = _lsb_extract_via_claude(text, regex_hints=regex_vals, label='lsb-primary')
            print(f"[LSB-parser] Claude: brutto={ai_vals.get('brutto',0):.2f} "
                  f"z17={ai_vals.get('ag_fahrt_z17',0):.2f} "
                  f"lohnsteuer={ai_vals.get('lohnsteuer',0):.2f}")

            # ── 3) Cross-Check + Diskrepanz-Resolution ──
            chosen = {}
            critical_fields = ['brutto', 'lohnsteuer', 'ag_fahrt_z17']
            disagreement = False
            for k in regex_vals.keys():
                rv = regex_vals.get(k, 0) or 0
                av = ai_vals.get(k, 0) or 0
                # Diskrepanz: beide Werte nicht 0 und differieren um >1 EUR oder >1%
                if rv > 0 and av > 0:
                    diff = abs(rv - av)
                    if diff > max(1.0, rv * 0.01):
                        if k in critical_fields:
                            disagreement = True
                            print(f"[LSB-parser] DISKREPANZ {k}: regex={rv:.2f} vs claude={av:.2f}")
                        chosen[k] = av  # KI gewinnt
                    else:
                        chosen[k] = av  # praktisch identisch, KI nehmen
                elif av > 0:
                    chosen[k] = av  # nur KI hat Wert
                elif rv > 0:
                    chosen[k] = rv  # nur Regex hat Wert (KI vermutlich offline)
                else:
                    chosen[k] = 0   # beide leer

            # Bei kritischer Diskrepanz: zweiter Claude-Call mit beiden Werten zur finalen Entscheidung
            if disagreement and ANTHROPIC_KEY:
                print(f"[LSB-parser] kritische Diskrepanz → Re-Check mit beiden Werten")
                resolution_text = (
                    "DISKREPANZ-RE-CHECK: Diese LSB wurde 2× gelesen mit unterschiedlichen Ergebnissen. "
                    "Lies JEDEN dieser Werte nochmal sorgfältig im PDF-Text nach. Achte auf Tausenderpunkte, "
                    "Kommas, korrekte Zeilen-Zuordnung. Gib das korrekte JSON zurück.\n"
                    "Vergleich der Quellen:\n" +
                    '\n'.join(f"  {k}: regex={regex_vals.get(k,0):.2f} vs claude={ai_vals.get(k,0):.2f}"
                              for k in critical_fields)
                )
                # Resolution als extra_instruction übergeben (nicht in text einbetten — wäre nach text[:10000] abgeschnitten)
                final_vals = _lsb_extract_via_claude(text, regex_hints=None,
                                                     label='lsb-recheck',
                                                     extra_instruction=resolution_text)
                if final_vals.get('brutto', 0) > 0:
                    print(f"[LSB-parser] Re-Check OK: brutto={final_vals.get('brutto',0):.2f}")
                    for k, v in final_vals.items():
                        if v > 0:
                            chosen[k] = v

            # Werte ins result-Dict übernehmen — bei mehreren LSB-PDFs (z.B. AG-Wechsel)
            # werden numerische Werte AKKUMULIERT, nicht überschrieben.
            for k in regex_vals.keys():
                v = chosen.get(k, 0) or 0
                if v > 0:
                    if isinstance(result.get(k), (int, float)):
                        result[k] = round((result[k] or 0) + v, 2)
                    else:
                        result[k] = v

            # ── 4) Persönliche Daten via Regex — nur setzen wenn noch nicht gesetzt
            # (bei Multi-LSB AG-Wechsel: erste LSB liefert die Stammdaten,
            #  zweite würde sonst überschreiben mit AG2-Werten)
            if result['brutto'] > 0:
                if not result.get('identnr'):
                    m_id = re.search(r'Identifikationsnummer:\s*(\d{11})', text)
                    if m_id: result['identnr'] = m_id.group(1)
                if not result.get('geburtsdatum'):
                    m_geb = re.search(r'Geburtsdatum:\s*(\d{2}\.\d{2}\.\d{4})', text)
                    if m_geb: result['geburtsdatum'] = m_geb.group(1)
                if not result.get('personalnummer'):
                    m_pnr = re.search(r'Personalnummer:\s*(\d+)', text)
                    if m_pnr: result['personalnummer'] = m_pnr.group(1)
                if result.get('steuerklasse') in (None, '', '1'):  # default ist '1'
                    m_sk = re.search(r'Steuerklasse/Faktor\s+(\d)', text)
                    if m_sk: result['steuerklasse'] = m_sk.group(1)
                if not result.get('kinderfreibetraege'):
                    m_kfb = re.search(r'Kinderfreibetr[^\d]+([\d,]+)', text)
                    if m_kfb:
                        try: result['kinderfreibetraege'] = float(m_kfb.group(1).replace(',','.'))
                        except: pass
                if not result.get('kirchensteuermerkmale'):
                    m_kst = re.search(r'Kirchensteuermerkmale\s+([\w\s/\-]+?)(?:\n|$)', text)
                    if m_kst: result['kirchensteuermerkmale'] = m_kst.group(1).strip()
                if not result.get('finanzamt'):
                    m_fa = re.search(r'Finanzamt[^\n]*\n([^\n]+)', text)
                    if m_fa: result['finanzamt'] = m_fa.group(1).strip()
                if not result.get('steuernummer_ag'):
                    m_stnr = re.search(r'Steuernummer:\s*([\d/]+)', text)
                    if m_stnr: result['steuernummer_ag'] = m_stnr.group(1)

                result['vorsorge_gesamt_an'] = round(
                    result['rv_an'] + result['kv_an'] +
                    result['pv_an'] + result['av_an'], 2)
                result['rv_gesamt'] = round(result['rv_an'] + result['rv_ag'], 2)
                print(f"[LSB-parser] FINAL brutto={result['brutto']:.2f} "
                      f"z17={result['ag_fahrt_z17']:.2f} disagreement={disagreement}")

        except Exception as e:
            print(f'[LSB-parser] PDF-Read fail: {e}')

    return result



def _claude_with_retry(client, model, max_tokens, content, max_retries=3, label='claude'):
    """Anthropic API mit exponential backoff. Schützt vor transienten Fehlern.

    P1 #74 Fix: Retry-Detection nutzt strukturierte Anthropic-Exception-Typen
    statt substring-match auf err-string. Substring-match hatte 5xx-Codes auch
    in legitimen 4xx-Error-Bodies erkannt (z.B. '500' in JSON-Beispielen) →
    Auth-Errors wurden 3× retryt mit gleichem 401-Resultat.
    """
    import time as _t
    try:
        import anthropic as _anthropic
    except Exception:
        _anthropic = None
    last_err = None
    for attempt in range(max_retries):
        try:
            return client.messages.create(model=model, max_tokens=max_tokens,
                                          messages=[{'role': 'user', 'content': content}])
        except Exception as e:
            last_err = e
            # Strukturiert: prüfe Anthropic-Exception-Typen
            should_retry = False
            if _anthropic is not None:
                # RateLimitError = 429
                if isinstance(e, getattr(_anthropic, 'RateLimitError', tuple())):
                    should_retry = True
                # APITimeoutError + APIConnectionError = network/transient
                elif isinstance(e, (
                    getattr(_anthropic, 'APITimeoutError', tuple()),
                    getattr(_anthropic, 'APIConnectionError', tuple()),
                )):
                    should_retry = True
                # InternalServerError = 5xx
                elif isinstance(e, getattr(_anthropic, 'InternalServerError', tuple())):
                    should_retry = True
                # APIStatusError mit .status_code 5xx
                elif isinstance(e, getattr(_anthropic, 'APIStatusError', tuple())):
                    sc = getattr(e, 'status_code', None)
                    if isinstance(sc, int) and 500 <= sc < 600:
                        should_retry = True
            if not should_retry or attempt == max_retries - 1:
                app.logger.error(
                    f"[{label}] failed attempt={attempt+1}/{max_retries} "
                    f"err={type(e).__name__}"
                )
                raise
            wait = 2 ** attempt + 1
            app.logger.warning(
                f"[{label}] retry attempt={attempt+1}/{max_retries} wait={wait}s "
                f"err={type(e).__name__}"
            )
            _t.sleep(wait)
    if last_err: raise last_err


def _claude_stream_with_retry(client, model, max_tokens, content, max_retries=3, label='claude-stream', prefill=None):
    """Wie _claude_with_retry, aber für Streaming-Calls. Liefert kompletten Text zurück.
    prefill (optional): String der als Anfang der Assistant-Antwort vorgegeben wird.
    Damit zwingt man Claude zu strukturierter Ausgabe (z.B. JSON) ohne Vorgeplänkel."""
    import time as _t
    last_err = None
    for attempt in range(max_retries):
        try:
            full_text = ''
            messages = [{'role': 'user', 'content': content}]
            if prefill:
                messages.append({'role': 'assistant', 'content': prefill})
            with client.messages.stream(model=model, max_tokens=max_tokens,
                                        messages=messages) as stream:
                for text in stream.text_stream:
                    full_text += text
            # Bei prefill: Antwort beginnt OHNE den prefill-String, also vorhängen
            if prefill:
                full_text = prefill + full_text
            return full_text.strip()
        except Exception as e:
            last_err = e
            err_str = str(e)
            should_retry = any(s in err_str.lower() for s in ['429', '500', '502', '503', '504', 'timeout', 'connection', 'rate'])
            if not should_retry or attempt == max_retries - 1:
                print(f"[{label}] failed (attempt {attempt+1}/{max_retries}): {err_str[:200]}")
                raise
            wait = 2 ** attempt + 1
            print(f"[{label}] retry attempt {attempt+1}/{max_retries} in {wait}s — {err_str[:120]}")
            _t.sleep(wait)
    if last_err: raise last_err


# ════════════════════════════════════════════════════════════════════════════
# Phase 2: KI-Resolver-Infrastruktur
# ════════════════════════════════════════════════════════════════════════════
#
# Aktive KI-Kontextauflösung NACH deterministic parser, VOR Userfrage.
# Source-of-Truth-Hierarchie:
#   1. deterministic parser/mapping
#   2. KI-Kontextresolver (diese Funktion)
#   3. Python-Steuerlogik/BMF
#   4. Userfrage (Last Resort)
#
# Eiserne Regel:
#   - KI darf Fakten/Kontext auflösen (Ort, Land, Code, Marker, Zeit, Layover-Ort)
#   - KI darf NIEMALS Steuerbeträge berechnen oder BMF-Pauschalen nennen
#   - Anti-Tax-Sanitizer rejected jeden value mit amount/eur/rate/betrag/euro/tagesatz
#
# Kontext-Regel:
#   - Jeder Prompt enthält Airline-Crew-Kontext (Flugpersonal, Cockpit/Kabine,
#     Lufthansa-ähnlich, Dienstplan/CAS/SE)
#   - Marker NIE kontextlos befragt
#
# Caching:
#   - In-Memory pro (job_id, datum, kind, context-hash), TTL 24h
#   - Verhindert wiederholte API-Calls für selben Fact
# ════════════════════════════════════════════════════════════════════════════

# Cache: (job_id, datum, kind, context_hash) → (result_dict, expires_at)
_ai_resolver_cache = {}
_AI_RESOLVER_CACHE_TTL_HOURS = 24
_AI_RESOLVER_MODEL = 'claude-sonnet-4-5'
_AI_RESOLVER_MAX_TOKENS = 512
_AI_RESOLVER_TIMEOUT_S = 30.0

# Confidence-Schwellen
_AI_CONF_AUTO_THRESHOLD = 0.90   # ≥ → resolved=True, needs_review=False
_AI_CONF_REVIEW_THRESHOLD = 0.70  # ≥ → resolved=True, needs_review=True
# < REVIEW → resolved=False, needs_review=True (Userfrage ohne Vorschlag)

# Verbotene Felder im value (Anti-Tax-Sanitizer)
_AI_FORBIDDEN_VALUE_KEYS = {
    'amount', 'eur', 'rate', 'betrag', 'euro', 'tagesatz',
    'pauschale', 'tax', 'steuer', 'an_abreise', 'voll_24h',
    'tagestrip_8h', 'price', 'preis', 'satz',
}

# Erlaubte resolver-Kinds
_AI_RESOLVER_KINDS = {
    'place_code',           # IATA/City/Metro-Code → Ort, Land
    'cas_time_extraction',  # Rohzeile → start/end/duty
    'marker_semantics',     # ORTSTAG/FRS/LMN → passive/active/office/etc
    'layover_place',        # overnight ohne layover_ort → wahrscheinlichster Ort
    'tour_context',         # mehrtägige Tour → Tour-Struktur/Zweck
    'tour_boundary',        # BH-CORE-001: Tour-Range + primary_destination aus context
    'standby_context',      # BH-CORE-001: RES/SB im Hotel vs zuhause
    'routing_consistency',  # Phase 5a: routing transit/Inkonsistenz-Klärung
}


def _ai_resolver_airline_crew_context_block():
    """Standard-Airline-Crew-Kontext-Header für alle Resolver-Prompts.
    P2 Regel: KEIN kontextloser KI-Call.

    Phase 5d/Master-A+B: nur Crew-Code-Vokabular aus repo-belegten Quellen
    (referenz_faelle.txt, app.py-Konstanten PASSIVE/SANDWICH/LAYOVER_FREE
    /EXCLUDE-Listen, tests/*.py-Assertions). Belege siehe
    docs/AEROTAX_CREW_CODE_GLOSSARY.md.

    Begriffe mit `needs_validation=true` (PUR, CR, FO, SECCRM, CRM, TRG,
    'Roster-ID'-Konzept) sind hier NICHT enthalten — sie sind Soft-
    Inferenzen, keine User-bestätigten Regeln.
    """
    return (
        "Du analysierst einen Dienstplan für Flugpersonal "
        "(Cockpit/Kabine, Airline-Crew, Lufthansa-ähnlicher Crew-Roster). "
        "Die Daten stammen aus CAS/Dienstplan, Streckeneinsatzabrechnung (SE) "
        "und/oder Lohnsteuerunterlagen (LSB).\n\n"
        "CREW-CODE-VOKABULAR (kritisch — nicht mit IATA-Codes verwechseln):\n"
        "  PU       = Purser / Kabinenchef / Crew-Position. "
        "**NICHT Pula-Airport (PUY)**.\n"
        "  P1, P2, P3, P4 = Position-Codes (Pilot 1..4 / Pattern-Slot). "
        "**NICHT Flughafen-Codes**.\n"
        "  PA       = (weitere Crew-Position in EXCLUDE-Liste; "
        "Bedeutung intern).\n"
        "  RES      = Reserve / Bereitschaftsdienst. Default zuhause = "
        "Arbeitstag, KEIN Fahrtag. Ausnahme: RES mit Inland-Übernachtung "
        "(HAM/MUC) = Z73-Kandidat (Schulung mit Hotel). RES nach "
        "foreign-overnight im Tour-Kontext = standby_hotel-Kandidat.\n"
        "  SBY, SB  = Standby (Synonym zu RES).\n"
        "  X        = streckenfrei-Tag / Layover-Off-Day. "
        "Innerhalb Tour (prev_overnight + foreign_layover): "
        "tour_mid (Layover-Free-Day im foreign Hotel). "
        "Zuhause ohne Tour-Continuity: Frei-Tag.\n"
        "  ==       = Layover-Continuation-Marker. Kontextabhängig wie X.\n"
        "  OFF, OF  = Off-Day (kein Dienst). Kontextabhängig wie X.\n"
        "  ORTSTAG  = lokaler Hb-Tag (passive Anwesenheit zuhause). NO_VMA.\n"
        "  FRS      = Office / Admin-Präsenz am Homebase. NO_VMA.\n"
        "  LMN, LMN_AS, LMN_CR = Lokale Maßnahmen / Training / Medical am "
        "Homebase. NO_VMA.\n"
        "  FRD      = (in PASSIVE_MARKERS, vermutlich Frei-Tag).\n\n"
        "TRAINING-MARKER (mit AT+FT-Regel — täglich Anfahrt zählt):\n"
        "  EM       = Erste-Hilfe-Maßnahmen / Briefing. AT + FT pro Tag.\n"
        "  EH       = Erste-Hilfe-Schulung. AT + FT pro Tag.\n"
        "  EK       = Bürodienst / Office. AT + FT pro Tag.\n"
        "  TK       = Kurzschulung. AT + FT.\n"
        "  D4       = Mehrtägige Präsenz-Schulung. JEDER Tag = AT + FT.\n"
        "  DD       = Seminar / Abordnung (mehrtägig). JEDER Tag = AT + FT.\n"
        "  Sequenz-Regel: 3+ aufeinanderfolgende EM/EH/D4-Tage OHNE FREI "
        "→ FAST IMMER Schulungs-Tour mit Hotel (Z73-Tour-Verdacht).\n\n"
        "FLIGHT-STATUS-MARKER:\n"
        "  FL       = Layover-Marker. EINE FL-Markierung IST EINE Hotelnacht "
        "(EASA ≥10h Bodenzeit). Hotel-Counter: Σ FL-Marker.\n\n"
        "INLAND-WHITELIST (für Z72/Z73-Klassifikation):\n"
        "  FRA, MUC, HAM, DUS, STR, CGN, BER, LEJ, NUE, BRE, HAJ, TXL, PAD.\n\n"
        "NUMERISCHE MARKER (Vorsicht — nicht im Repo explizit definiert):\n"
        "  Ein 5-6-stelliger numerischer Block (z.B. 103703, 32935, 57783) "
        "*scheint* in den Fixture-Daten als Crew-Sequenz-/Roster-ID zu "
        "fungieren, NICHT als LH-Flugnummer (LH-Nummern sind 3-4-stellig "
        "wie LH404). Diese Interpretation ist **nicht formal user-bestätigt** "
        "— bei Mismatch zu CAS-Routing/SE prüfe vor Auto-Übernahme.\n"
        "  Format wie '129023 PU / Tag 3' = (Roster-ID) + (Position-Code) + "
        "(Day-Sequence-Suffix); PU ist Position-Code, NICHT Pula.\n\n"
        "IATA-SOURCE-REGEL (kritisch):\n"
        "  IATA-/Place-Codes bevorzugt aus `routing`, `se.stfrei_ort` oder "
        "`layover_ort`. NICHT aus der raw_marker-Spalte raten. Die "
        "EXCLUDE-Liste (intern app.py:14114) sammelt alle Status-/Position-"
        "Codes die NICHT als IATA missverstanden werden dürfen: "
        "RES, SBY, OFF, ORTSTAG, FRS, FRD, LMN(.*), EM, OF, P1..P4, PU, PA.\n\n"
        "FOLLOWME / GOLDEN ist eine externe REFERENZ, NICHT die Wahrheit. "
        "CAS + SE + Plausibilität bleiben Primärquellen. Bei CAS↔FollowMe-"
        "Place-Konflikt → reader_misread-Verdacht oder NEEDS_REVIEW, "
        "NICHT blind CAS bestätigen.\n"
    )


def _ai_resolver_kind_context(kind):
    """Kind-spezifischer Kontext-Hinweis im Prompt."""
    if kind == 'place_code':
        return (
            "Der Code stammt aus einem Airline-Crew-Dienstplan oder "
            "Streckeneinsatz. Es kann ein Airport-Code (3 Buchstaben, ICAO/IATA), "
            "City-Code, Metro-Area-Code (z.B. CHI/ROM/STO/LON/NYC), Layover-Ort "
            "oder Airline-Station-Code sein."
        )
    if kind == 'cas_time_extraction':
        return (
            "Die Zeile stammt aus einem Crew-Dienstplan. Extrahiere Start/Ende/"
            "Ort/Aktivität falls vorhanden. Briefingzeit ist Dienstbeginn, "
            "Landung+Debriefing ist Dienstende. Bei Office/Schulung gilt die "
            "im Plan stehende Zeitspanne."
        )
    if kind == 'marker_semantics':
        return (
            "Der Marker stammt aus einem Airline-Crew-Roster für Cockpit/Kabine. "
            "Beurteile NUR anhand des gegebenen Crew-Kontexts und der Nachbarzeilen, "
            "ob der Marker wahrscheinlich aktiver Dienst, passive Reserve/zuhause, "
            "Office/Schulung oder Reise-/Layover-Kontext ist. Vergleiche mit "
            "Nachbartagen und SE-Spesen."
        )
    if kind == 'layover_place':
        return (
            "Die Daten stammen aus einer Flugdienst-Tour. Bestimme den "
            "wahrscheinlichsten Layover-Ort aus Routing, Vortag/Folgetag, "
            "SE-Spesenort und Crew-Tour-Logik. Tour-Cluster bedeutet "
            "mehrtägige Flugsequenz mit Übernachtungen vor Rückkehr zur Homebase."
        )
    if kind == 'tour_context':
        return (
            "Dies ist eine Crew-Tour mit Flügen, Standby, Briefingzeiten, "
            "Layovern und Rückkehr zur Homebase. Analysiere den Tour-"
            "Zusammenhang, nicht isoliert den einzelnen Tag."
        )
    return ''


def _ai_resolver_value_safe(value):
    """Anti-Tax-Sanitizer: prüft ob value verbotene Felder enthält
    (Steuerbeträge / BMF-Pauschalen / monetäre Werte).
    Returns (is_safe, offending_key)."""
    if not isinstance(value, dict):
        return (True, None)
    for k in value.keys():
        if not isinstance(k, str):
            continue
        if k.lower() in _AI_FORBIDDEN_VALUE_KEYS:
            return (False, k)
    return (True, None)


def _ai_resolver_context_hash(context):
    """Stabile Hash über context-dict (für Cache-Key).
    Sortiert Keys damit gleicher Context → gleicher Hash."""
    try:
        canonical = json.dumps(context, sort_keys=True, default=str)
    except Exception:
        canonical = str(context)
    return _hashlib.sha256(canonical.encode('utf-8')).hexdigest()[:16]


# ─── Phase-5b PII-Hardening — Prompt-Builder Whitelist ─────────────────────

# Erlaubte Feldnamen für Top-Level-Context und für day/prev_day/next_day-Dicts
_AI_SAFE_PLAN_FIELDS = frozenset({
    'datum', 'kind', 'marker', 'raw_marker',
    'activity_type', 'routing', 'start_time', 'end_time',
    'duty_duration_minutes', 'overnight_after_day',
    'layover_ort', 'starts_at_homebase', 'ends_at_homebase',
    'has_fl', 'is_workday', 'requires_commute',
    # Whitelist für evidence-items (lists of (name, weight, detail))
    'evidence_for', 'evidence_against',
    # KI-Resolver-Felder
    'score_for', 'score_against', 'evidence_decision',
})

# Erlaubte Feldnamen für SE-Sub-Dict
_AI_SAFE_SE_FIELDS = frozenset({
    'stfrei_ort', 'stfrei_inland',
    'se_has_allowance', 'se_amount_present',
    'count', 'zwoelftel',
})

# Erlaubte Felder im followme_context (anonymisiert)
_AI_SAFE_FM_FIELDS = frozenset({
    'tour_span', 'tour_country', 'tour_role',
    'position_in_tour', 'has_anfahrt',
    'in_any_tour_span', 'expected_destinations',
    'tour_destination', 'tour_size',
})

# Explizit verbotene Felder (PII / Secrets / Payment / Raw-Files)
_AI_PII_FORBIDDEN_FIELDS = frozenset({
    # Personen-Identifikatoren
    'name', 'vorname', 'nachname', 'fullname', 'first_name', 'last_name',
    'mitarbeiter', 'mitarbeiter_nr', 'mitarbeiter_id',
    'personalnummer', 'personal_nr', 'personnel_id',
    'employee_id', 'employee_name', 'employee_number',
    'pnr', 'crewid', 'crew_id', 'crewmember_id',
    'birthdate', 'date_of_birth', 'dob',
    'email', 'mail', 'email_address',
    'phone', 'telefon', 'mobile',
    'address', 'adresse', 'street', 'strasse',
    'plz', 'postal_code', 'zip',
    'iban', 'bic', 'bank_account',
    'tax_id', 'steuer_id', 'steuernummer', 'steuer_nr', 'tin',
    'sozialversicherung', 'social_security',
    # Raw-Files / PDF-Inhalte
    'raw_pdf_text', 'pdf_bytes', 'pdf_content', 'pdf_data',
    'file_content', 'file_bytes', 'file_data', 'raw_bytes',
    'raw_lines',  # CAS raw_lines können PII enthalten
    # Filenames / Pfade
    'filename', 'filepath', 'file_path', 'original_filename',
    'pdf_filename', 'pdf_path', 'upload_path',
    # Session / Tokens / Payment
    'session_token', 'recovery_token', 'access_token',
    'refresh_token', 'auth_token', 'api_token',
    'payment_intent', 'payment_intent_id', 'stripe_id', 'stripe_session',
    'stripe_customer', 'stripe_payment',
    # Storage-IDs
    'supabase_id', 'supabase_user_id', 'storage_id',
    'job_owner_id', 'user_id', 'auth_user_id',
    # Misc-PII
    'anrede', 'titel', 'salutation',
    'geburtsort', 'geburtsdatum',
    'wohnort',
})


def _ai_resolver_safe_context(context):
    """Phase-5b PII-Hardening: liefert sanitiertes Kontext-Dict für KI-Prompts.

    Regeln:
      - Top-Level: nur Whitelist-Felder + 'day', 'prev_day', 'next_day', 'se',
        'homebase', 'evidence_for', 'evidence_against'.
      - day/prev_day/next_day: nur Plan-Fakten (kein raw_lines, kein PNR etc).
      - se: stfrei_ort, stfrei_inland, count; KEIN stfrei_total (Tax-Wert).
      - followme: nur anonymisierte Aggregate (kein job_id, kein token).
      - evidence_for/against: nur (name, weight, detail-string).
      - PII-Schwarzliste (`_AI_PII_FORBIDDEN_FIELDS`) wird IMMER entfernt,
        rekursiv auf allen Ebenen.
    """
    if not isinstance(context, dict):
        return {}

    def _strip_pii_recursive(node):
        if isinstance(node, dict):
            out = {}
            for k, v in node.items():
                ks = str(k).lower().strip()
                if ks in _AI_PII_FORBIDDEN_FIELDS:
                    continue
                # Substring-Match auf bekannte PII-Tokens (defensiv)
                if any(tok in ks for tok in (
                        'password', 'secret', 'token', 'apikey', 'api_key',
                        'auth', 'session', 'cookie',
                )):
                    continue
                out[k] = _strip_pii_recursive(v)
            return out
        if isinstance(node, list):
            return [_strip_pii_recursive(x) for x in node]
        return node

    def _filter_day(d):
        if not isinstance(d, dict):
            return d
        cleaned = _strip_pii_recursive(d)
        # Whitelist nur Plan-Fakten
        return {k: v for k, v in cleaned.items() if k in _AI_SAFE_PLAN_FIELDS}

    def _filter_se(s):
        if not isinstance(s, dict):
            return {}
        cleaned = _strip_pii_recursive(s)
        out = {k: v for k, v in cleaned.items() if k in _AI_SAFE_SE_FIELDS}
        # Tax-Wert (`stfrei_total`) NICHT in Prompt
        out.pop('stfrei_total', None)
        # Add booleanized se_has_allowance
        try:
            cnt = int(cleaned.get('count') or 0)
            out['se_has_allowance'] = bool(cnt > 0)
        except (TypeError, ValueError):
            out['se_has_allowance'] = False
        return out

    def _filter_fm(f):
        if not isinstance(f, dict):
            return {}
        cleaned = _strip_pii_recursive(f)
        return {k: v for k, v in cleaned.items() if k in _AI_SAFE_FM_FIELDS}

    safe = {}
    # day / prev_day / next_day
    for key in ('day', 'prev_day', 'next_day'):
        if context.get(key) is not None:
            safe[key] = _filter_day(context.get(key))
    # se
    if context.get('se') is not None:
        safe['se'] = _filter_se(context.get('se'))
    # homebase (nur IATA-Code)
    hb = context.get('homebase')
    if hb:
        safe['homebase'] = str(hb).upper()[:6]
    # followme_context (anonymisiert)
    fm = context.get('followme_context') or context.get('fm')
    if fm:
        safe['followme'] = _filter_fm(fm)
    # evidence_for / evidence_against: sanitize, behalten
    for key in ('evidence_for', 'evidence_against'):
        items = context.get(key)
        if items and isinstance(items, list):
            safe[key] = []
            for item in items:
                if isinstance(item, (list, tuple)) and len(item) >= 2:
                    # (name, weight, optional detail)
                    name = str(item[0])[:80]
                    weight = item[1]
                    detail = str(item[2])[:140] if len(item) >= 3 else ''
                    safe[key].append([name, weight, detail])
                else:
                    # defensive: nur string
                    safe[key].append(str(item)[:140])
    # generische Top-Level-Felder (Whitelist)
    for k in ('datum', 'kind', 'marker', 'raw_marker', 'score_for',
              'score_against', 'evidence_decision'):
        if context.get(k) is not None:
            safe[k] = context[k]

    # Phase 5d — Cross-Source-Konflikt-Aggregation
    # Aus evidence_against + day-Fakten + SE + FollowMe rekonstruieren WARUM
    # die Evidence-Engine unsicher ist. Das hilft KI, den Konflikt direkt
    # zu adressieren statt naiv das CAS-Routing zu bestätigen.
    ag_names = set()
    for item in (context.get('evidence_against') or []):
        if isinstance(item, (list, tuple)) and len(item) >= 1:
            ag_names.add(str(item[0]))

    why_uncertain = []
    if 'cas_followme_place_conflict' in ag_names:
        why_uncertain.append(
            'CAS-routing zeigt einen Ort, FollowMe-Tour-Destinations zeigen '
            'einen anderen Ort. Mögliches reader_misread oder echte Diskrepanz.'
        )
    if 'day_suffix_claims_completed_prev' in ag_names:
        why_uncertain.append(
            'Marker hat „Tag N≥2" Suffix, aber Vortag war laut FollowMe eine '
            'abgeschlossene Tour. Day-Suffix könnte legitim sein (Multi-Day-'
            'Duty) ODER Reader-Bug.'
        )
    if 'transit_via_homebase_ends_foreign' in ag_names:
        why_uncertain.append(
            'Routing hat Homebase mittig als Transit, endet aber im Ausland. '
            'KEIN normaler Same-Day-Homebase-Return.'
        )
    if 'routing_inconsistent' in ag_names:
        why_uncertain.append(
            'starts_at_homebase/ends_at_homebase widerspricht routing[0]/[-1].'
        )
    if 'duty_over_ftl' in ag_names:
        why_uncertain.append(
            'duty_duration > FTL-Limit (840min). Reader-Bug-Verdacht.'
        )
    if 'no_homebase_commute_evidence' in ag_names:
        why_uncertain.append(
            'Tag claimt Hb-Departure, aber keine Anfahrt in der Anfahrten-Liste.'
        )
    if 'no_se_allowance' in ag_names and 'followme_explicit_other_span' in ag_names:
        why_uncertain.append(
            'Keine SE-Auslandsspesen-Zeile UND nicht in FollowMe-Tour-Spans — '
            'Phantom-Tag-Verdacht oder echte Tour ohne Beleg.'
        )
    if 'day_already_in_other_tour' in ag_names:
        why_uncertain.append(
            'FollowMe ordnet diesen Tag explizit einer ANDEREN Tour zu.'
        )
    if why_uncertain:
        safe['why_evidence_uncertain'] = why_uncertain

    # SE/Anfahrt-Presence-Boolean — kompakt für KI-Entscheidung
    se_obj = context.get('se') or {}
    if isinstance(se_obj, dict):
        safe['se_has_foreign_allowance'] = bool(
            int(se_obj.get('count') or 0) > 0
            and se_obj.get('stfrei_inland') is False
        )
    fm_obj = context.get('followme_context') or context.get('fm') or {}
    if isinstance(fm_obj, dict):
        anf = fm_obj.get('anfahrten_dates') or fm_obj.get('has_anfahrt')
        if anf is not None:
            safe['has_anfahrt_evidence'] = bool(anf)

    return safe


def _ai_resolver_build_prompt(kind, context, uncertain_fact):
    """Baut den User-Prompt mit Crew-Kontext-Header + kind-spezifischem Block.

    Phase-5b PII-Hardening: nutzt `_ai_resolver_safe_context` als Whitelist-
    Filter. Output: string. Wird in der Resolver-Funktion an
    client.messages.create gegeben.
    """
    base = _ai_resolver_airline_crew_context_block()
    kind_ctx = _ai_resolver_kind_context(kind)

    # PII-Sanitisierung: nur Whitelist-Felder gelangen in den Prompt
    safe_ctx = _ai_resolver_safe_context(context)
    ctx_lines = []
    for ck, cv in safe_ctx.items():
        if ck == 'uncertain_fact':
            continue
        try:
            ctx_lines.append(f"  {ck}: {json.dumps(cv, ensure_ascii=False, default=str)}")
        except Exception:
            ctx_lines.append(f"  {ck}: {str(cv)[:200]}")
    ctx_block = '\n'.join(ctx_lines[:30])  # Hard-Cap gegen riesige Prompts

    # uncertain_fact wird selbst sanitisiert (max 80 Zeichen, kein Email-Pattern)
    safe_fact = str(uncertain_fact or '')[:80]
    if '@' in safe_fact:
        safe_fact = safe_fact.split('@', 1)[0][:40]

    # Phase 5d — Cross-Source-Konflikt-Erklärung im Prompt
    conflict_note = ''
    why = safe_ctx.get('why_evidence_uncertain') or []
    if why:
        conflict_note = (
            '\nWARUM EVIDENCE-ENGINE UNSICHER IST '
            '(Cross-Source-Konflikte):\n'
            + ''.join(f'  - {w}\n' for w in why)
            + '\n'
        )

    return (
        f"{base}\n"
        f"Resolver-Aufgabe: {kind}\n"
        f"{kind_ctx}\n\n"
        f"Plan-Kontext (anonymisiert, PII-gefiltert):\n{ctx_block}\n"
        f"{conflict_note}"
        f"\nUnsicherer Fakt: {safe_fact}\n\n"
        f"Frage: Wie soll dieser Tag im Tour-Kontext eingeordnet werden?\n\n"
        f"Antwortformat (NUR strict JSON, keine Begleitzeilen):\n"
        f"{{\n"
        f'  "resolved": true|false,\n'
        f'  "decision": "KEEP_TOUR" | "DROP_TOUR" | "NEEDS_REVIEW",\n'
        f'  "context_type": "tour_day" | "homebase_free" | "homebase_standby"\n'
        f'                 | "hotel_standby" | "reader_misread" | "routing_conflict"\n'
        f'                 | "positioning" | "unknown",\n'
        f'  "value": {{"resolved_place": "...", "country": "...", "bmf_key": "..."}} '
        f'oder beschreibend,\n'
        f'  "confidence": 0.0-1.0,\n'
        f'  "reason": "kurze Begründung mit Evidenz",\n'
        f'  "evidence": ["Beleg aus Plan-Zeilen"],\n'
        f'  "needs_review": true|false\n'
        f"}}\n\n"
        f"REGELN für decision:\n"
        f"  - KEEP_TOUR nur wenn CAS+SE+Plausibilität konsistent. "
        f"Bei FollowMe-Place-Konflikt: NICHT blind KEEP — eher reader_misread oder NEEDS_REVIEW.\n"
        f"  - DROP_TOUR wenn der Tag im Tour-Kontext nicht plausibel ist "
        f"(kein SE-Stempel, keine Anfahrt-Evidence, FREI-Lücke um den Tag, "
        f"keine prev/next-Continuity). Verdacht reader_misread / Sequence-ID.\n"
        f"  - NEEDS_REVIEW wenn ambig — z.B. RES nach foreign-overnight "
        f"(könnte standby_hotel ODER standby_home sein und konkret abhängig von "
        f"Folgetag-Continuity), oder Phantom-Tag mit foreign-Routing aber ohne "
        f"SE-Stempel.\n\n"
        f"REGELN für context_type:\n"
        f"  - tour_day: echter Tour-Tag mit Flug+Layover+SE-Stempel\n"
        f"  - homebase_free: Frei-Tag zuhause, kein Dienst\n"
        f"  - homebase_standby: RES/SB zuhause, kein Tour-Kontext\n"
        f"  - hotel_standby: RES/SB im foreign Hotel während Tour\n"
        f"  - reader_misread: CAS-Reader hat falsch gelesen (z.B. JFK vs SNN)\n"
        f"  - routing_conflict: Routing widerspricht sich selbst oder dem Tour-Kontext\n"
        f"  - positioning: Crew-Positionierungs-Flug (FRA→X→FRA same-day, Crew transfer)\n"
        f"  - unknown: nicht eindeutig\n\n"
        f"REGELN für confidence:\n"
        f"  - ≥0.90 nur wenn alle drei Quellen (CAS, SE/Anfahrt, FollowMe falls "
        f"vorhanden) konsistent sind. Cross-Source-Konflikt → max 0.85.\n"
        f"  - 0.70-0.89 wenn Entscheidung defensible aber Konflikt-Hinweise vorliegen.\n"
        f"  - <0.70 wenn unklar.\n\n"
        f"VERBOTEN: KEINE Steuerbeträge, Pauschalen, Euro-Werte, Tagesätze, "
        f"BMF-Sätze, amount/eur/rate/betrag/tax/steuer-Felder. "
        f"Antworte nur mit faktischer Kontext-Klassifikation."
    )


def _ai_resolver_apply_thresholds(parsed):
    """Wendet die globalen Confidence-Schwellen an.
    Setzt resolved/needs_review-Flags konsistent."""
    conf = float(parsed.get('confidence', 0.0) or 0.0)
    if conf >= _AI_CONF_AUTO_THRESHOLD:
        parsed['resolved'] = True
        parsed['needs_review'] = False
    elif conf >= _AI_CONF_REVIEW_THRESHOLD:
        parsed['resolved'] = True
        parsed['needs_review'] = True
    else:
        parsed['resolved'] = False
        parsed['needs_review'] = True
    return parsed


def _ai_resolver_review_fallback(reason='unknown_failure'):
    """Standard-Fallback-Result wenn KI nicht antwortet/invalid/sanitizer-reject."""
    return {
        'resolved':     False,
        'value':        {},
        'confidence':   0.0,
        'reason':       reason,
        'evidence':     [],
        'needs_review': True,
    }


def _resolve_uncertain_fact_with_ai(kind, context, job_id=None, datum=None,
                                     uncertain_fact='', _anthropic_client=None,
                                     _force_mock=False):
    """Aktiver KI-Kontextresolver. Ruft Sonnet 4.5 mit Airline-Crew-Kontext auf
    und liefert strukturierten Fakt zurück (KEIN Steuerbetrag).

    Parameters:
      kind     — einer von _AI_RESOLVER_KINDS
      context  — dict mit Plan-Fakten (raw CAS lines, SE-fakten, Nachbartage, etc.)
      job_id   — für Cache-Scope (optional)
      datum    — für Cache-Scope (optional)
      uncertain_fact — der konkrete Fakt der aufgelöst werden soll (z.B. 'CHI', 'ORTSTAG')
      _anthropic_client — DI für Tests (sonst lazy-loaded)

    Returns:
      {
        'resolved': bool,
        'value': dict,
        'confidence': float,
        'reason': str,
        'evidence': list[str],
        'needs_review': bool,
      }

    Garantien:
      - Verbotene value-Keys (amount/eur/rate/...) → reject, needs_review=True
      - Invalid JSON → review-fallback
      - Timeout / API-Error → review-fallback
      - Max 1 retry bei JSON-invalid
      - Cache pro (job_id, datum, kind, context-hash) für TTL Stunden
      - Audit-Log ohne PII (nur kind/conf/resolved)
    """
    # Validate kind
    if kind not in _AI_RESOLVER_KINDS:
        return _ai_resolver_review_fallback(f'unknown_kind:{kind}')

    # Cache-Key
    ctx_hash = _ai_resolver_context_hash(context)
    cache_key = (job_id or 'no_job', datum or 'no_datum', kind, ctx_hash)
    now = datetime.utcnow()
    cached = _ai_resolver_cache.get(cache_key)
    if cached:
        result, expires_at = cached
        if expires_at > now:
            return dict(result)  # Defensive copy
        # Expired → drop
        _ai_resolver_cache.pop(cache_key, None)

    # Phase 5a — Mock-Mode-Bypass.
    # Aktiv wenn:
    #   - _force_mock=True (explicit shadow-integration request), ODER
    #   - env-Var AEROTAX_AI_RESOLVER_MODE=mock UND kein _anthropic_client injected.
    # Default-Verhalten bleibt unverändert (Anthropic-Call wenn API-Key vorhanden),
    # damit Legacy-Tests + _get_bmf_for_iata-Path unangetastet bleiben.
    _resolver_mode = (os.environ.get('AEROTAX_AI_RESOLVER_MODE') or 'live').lower().strip()
    if (_force_mock or
            (_resolver_mode == 'mock' and _anthropic_client is None)):
        try:
            mock_raw = _ai_resolver_mock_dispatch(kind, context or {})
        except Exception as e:
            return _ai_resolver_review_fallback(f'mock_error:{type(e).__name__}')
        # Anti-Tax-Sanitizer auch auf Mock-Output anwenden
        mval = mock_raw.get('value') if isinstance(mock_raw.get('value'), dict) else {}
        safe, offending = _ai_resolver_value_safe(mval)
        if not safe:
            result = _ai_resolver_review_fallback(
                f'value_contains_forbidden_key:{offending}'
            )
            expires = now + timedelta(hours=_AI_RESOLVER_CACHE_TTL_HOURS)
            _ai_resolver_cache[cache_key] = (result, expires)
            return dict(result)
        # Phase 5d — structured fields (decision + context_type) durchreichen
        _ALLOWED_DECISIONS = ('KEEP_TOUR', 'DROP_TOUR', 'NEEDS_REVIEW')
        _ALLOWED_CONTEXTS = (
            'tour_day', 'homebase_free', 'homebase_standby',
            'hotel_standby', 'reader_misread', 'routing_conflict',
            'positioning', 'unknown',
        )
        m_dec = str(mock_raw.get('decision') or '').upper().strip()
        m_dec = m_dec if m_dec in _ALLOWED_DECISIONS else 'NEEDS_REVIEW'
        m_ctx = str(mock_raw.get('context_type') or '').lower().strip()
        m_ctx = m_ctx if m_ctx in _ALLOWED_CONTEXTS else 'unknown'
        result = {
            'resolved':     bool(mock_raw.get('resolved', False)),
            'decision':     m_dec,
            'context_type': m_ctx,
            'value':        mock_raw.get('value'),
            'confidence':   float(mock_raw.get('confidence') or 0.0),
            'reason':       str(mock_raw.get('reason') or '')[:300],
            'evidence':     [str(e)[:200] for e in (mock_raw.get('evidence') or [])[:5]],
            'needs_review': bool(mock_raw.get('needs_review', False)),
        }
        result = _ai_resolver_apply_thresholds(result)
        expires = now + timedelta(hours=_AI_RESOLVER_CACHE_TTL_HOURS)
        _ai_resolver_cache[cache_key] = (result, expires)
        try:
            app.logger.info(
                f"[ai-resolver-mock] kind={kind} conf={result['confidence']:.2f} "
                f"resolved={result['resolved']} needs_review={result['needs_review']}"
            )
        except Exception:
            pass
        return dict(result)

    # Lazy-load Anthropic client (oder via DI für Tests)
    client = _anthropic_client
    if client is None:
        try:
            import anthropic as _anthropic_mod
            api_key = os.environ.get('ANTHROPIC_API_KEY', '')
            if not api_key:
                return _ai_resolver_review_fallback('no_api_key')
            client = _anthropic_mod.Anthropic(api_key=api_key, timeout=_AI_RESOLVER_TIMEOUT_S)
        except Exception as e:
            app.logger.warning(
                f"[ai-resolver] anthropic_init_fail kind={kind} err={type(e).__name__}"
            )
            return _ai_resolver_review_fallback('anthropic_init_failed')

    prompt = _ai_resolver_build_prompt(kind, context, uncertain_fact)

    # Call mit max 1 retry bei JSON-invalid
    parsed = None
    last_error = None
    for attempt in range(2):
        try:
            resp = client.messages.create(
                model=_AI_RESOLVER_MODEL,
                max_tokens=_AI_RESOLVER_MAX_TOKENS,
                messages=[{'role': 'user', 'content': prompt}],
            )
            # Anthropic-Response: resp.content[0].text
            text = ''
            try:
                text = resp.content[0].text if resp.content else ''
            except (AttributeError, IndexError):
                text = str(resp)
            # JSON parsen
            try:
                # Erstes „{ ... }" aus dem Text extrahieren (falls Vorgeplänkel)
                first_brace = text.find('{')
                last_brace = text.rfind('}')
                if first_brace < 0 or last_brace < 0:
                    raise ValueError('no_json_braces')
                parsed = json.loads(text[first_brace:last_brace + 1])
                break  # erfolgreich
            except (ValueError, json.JSONDecodeError) as e:
                last_error = f'json_invalid:{type(e).__name__}'
                if attempt == 0:
                    # Retry mit Strict-Hint
                    continue
        except Exception as e:
            last_error = f'api_error:{type(e).__name__}'
            app.logger.warning(
                f"[ai-resolver] api_fail kind={kind} attempt={attempt+1} err={type(e).__name__}"
            )
            break  # API-Fehler: kein retry (Cost-Schutz)

    if parsed is None:
        result = _ai_resolver_review_fallback(last_error or 'parse_failed')
        # Cache auch failure (verhindert wiederholte Calls)
        expires = now + timedelta(hours=_AI_RESOLVER_CACHE_TTL_HOURS)
        _ai_resolver_cache[cache_key] = (result, expires)
        return dict(result)

    # Anti-Tax-Sanitizer
    val = parsed.get('value') if isinstance(parsed.get('value'), dict) else {}
    safe, offending = _ai_resolver_value_safe(val)
    if not safe:
        app.logger.warning(
            f"[ai-resolver] value_rejected kind={kind} reason=forbidden_key:{offending}"
        )
        result = _ai_resolver_review_fallback(f'value_contains_forbidden_key:{offending}')
        expires = now + timedelta(hours=_AI_RESOLVER_CACHE_TTL_HOURS)
        _ai_resolver_cache[cache_key] = (result, expires)
        return dict(result)

    # Phase 5d: structured-output fields (decision + context_type)
    _ALLOWED_DECISIONS = ('KEEP_TOUR', 'DROP_TOUR', 'NEEDS_REVIEW')
    _ALLOWED_CONTEXTS = (
        'tour_day', 'homebase_free', 'homebase_standby',
        'hotel_standby', 'reader_misread', 'routing_conflict',
        'positioning', 'unknown',
    )
    raw_decision = str(parsed.get('decision') or '').upper().strip()
    decision = raw_decision if raw_decision in _ALLOWED_DECISIONS else 'NEEDS_REVIEW'
    raw_ctx_type = str(parsed.get('context_type') or '').lower().strip()
    context_type = raw_ctx_type if raw_ctx_type in _ALLOWED_CONTEXTS else 'unknown'

    # Confidence-Schwellen anwenden (override resolved/needs_review)
    result = {
        'resolved':     bool(parsed.get('resolved', False)),
        'decision':     decision,
        'context_type': context_type,
        'value':        val,
        'confidence':   float(parsed.get('confidence', 0.0) or 0.0),
        'reason':       str(parsed.get('reason', ''))[:300],
        'evidence':     [str(e)[:200] for e in (parsed.get('evidence') or [])[:5]],
        'needs_review': bool(parsed.get('needs_review', False)),
    }
    result = _ai_resolver_apply_thresholds(result)

    # Cache + Audit (ohne PII)
    expires = now + timedelta(hours=_AI_RESOLVER_CACHE_TTL_HOURS)
    _ai_resolver_cache[cache_key] = (result, expires)
    app.logger.info(
        f"[ai-resolver] resolved kind={kind} conf={result['confidence']:.2f} "
        f"resolved={result['resolved']} needs_review={result['needs_review']}"
    )
    return dict(result)


