_CAS_TO_DP_ACTIVITY_MAP = {
    'flight':    'tour',       # via overnight-Check ggf. zu 'same_day' überschrieben
    'office':    'office',
    'training':  'training',
    'simulator': 'training',   # closest DP-Equivalent (kein 'simulator' im DP-Enum)
    'standby':   'standby',
    'vacation':  'urlaub',
    'sick':      'krank',
    'free':      'frei',
    'layover':   'tour',       # v11 FollowMe-Fix: Mid-Tour-Layover wird wie tour klassifiziert
    'unknown':   'unknown',
}


# ════════════════════════════════════════════════════════════════════════════
# v11 FollowMe-Align — Pre-Klassifikator-Pass für Tour-Aware-Klassifizierung
# ════════════════════════════════════════════════════════════════════════════
def _followme_pre_classify_layover(cas_days):
    """v11 Fix F1: CAS-Tage mit Marker X/OFF/== zwischen Tour-Start und Tour-Ende
    werden zu activity_type='layover' reklassifiziert.

    Hintergrund:
    Der Sonnet-CAS-Reader klassifiziert „X", „OFF", „==" pauschal als
    `activity_type='free'`. Aber:
    - Diese Marker ZWISCHEN einer offenen Tour (overnight=True) und einem
      späteren Tour-Heimkehr-Tag bedeuten *Layover am Tour-Zielort*.
    - Erst dadurch werden Auslands-Layover-Tage richtig als Z76 erkannt
      und Hotel-Nächte gezählt.

    Algorithmus:
      1. Sortiere cas_days nach Datum
      2. Tour-State-Machine:
         - Tour-OPEN bei activity='flight' UND overnight_after_day=True
         - Tour-CLOSE bei activity='flight' UND overnight_after_day=False
           (Heimkehrtag)
      3. Während Tour-OPEN: alle activity='free' Tage zu 'layover'
         reklassifizieren, mit layover_ort vom vorigen Tag/Tour-Start

    Mutates cas_days in-place (auch return für Chaining).
    """
    if not cas_days or not isinstance(cas_days, list):
        return cas_days
    sorted_days = sorted([d for d in cas_days if isinstance(d, dict) and d.get('date')],
                         key=lambda d: d['date'])
    tour_open = False
    last_layover_ort = None
    last_country_iata = None
    reclass_count = 0
    for d in sorted_days:
        at = (d.get('activity_type') or '').lower()
        overnight = bool(d.get('overnight_after_day'))
        if at == 'flight':
            if overnight:
                # Tour bleibt/öffnet
                tour_open = True
                # Layover-Ort merken (vom Tag selber wenn vorhanden)
                lo = (d.get('layover_ort') or '').upper().strip()
                if lo:
                    last_layover_ort = lo
            else:
                # Heimkehr — Tour schließt nach diesem Tag
                tour_open = False
                last_layover_ort = None
        elif at == 'free' and tour_open and last_layover_ort:
            # Mid-Tour-Free → Reklassifiziere zu Layover
            d['activity_type'] = 'layover'
            d['_followme_reclassified'] = True
            d['_followme_reclassified_from'] = 'free'
            if not d.get('layover_ort'):
                d['layover_ort'] = last_layover_ort
            # overnight_after_day setzen, falls letzter Layover-Tag ist nicht klar
            # (wird vom nachfolgenden Heimkehr-Tag implizit gehandelt)
            reclass_count += 1
    if reclass_count:
        print(f"[followme-pre-classify] {reclass_count} Mid-Tour-Frei-Tage zu Layover reklassifiziert")
    return cas_days


def _cas_day_to_dp_format(cas_day, year=2025, homebase='FRA'):
    """v11: Konvertiert einen CAS-Tag-Eintrag zu DP-Format.

    Damit kann der bestehende Klassifikator (_deterministic_classify_v7) ohne
    Anpassung weiterverwendet werden. CAS-spezifische Felder (start_time,
    end_time, duration_minutes) bleiben zusätzlich erhalten für künftige
    v11-spezifische Logik (z.B. echtes Z72 via >480min statt nur Activity-Marker).
    """
    if not isinstance(cas_day, dict):
        return None
    cas_at = (cas_day.get('activity_type') or 'unknown').lower()
    dp_at = _CAS_TO_DP_ACTIVITY_MAP.get(cas_at, 'unknown')

    overnight = bool(cas_day.get('overnight_after_day'))
    # Flight ohne Layover-Übernachtung → same_day-Trip (FRA-X-FRA gleicher Tag)
    if dp_at == 'tour' and not overnight:
        dp_at = 'same_day'

    # Routing aus flights[] aufbauen
    routing = []
    flights = cas_day.get('flights') or []
    for f in flights:
        if not isinstance(f, dict): continue
        fr = (f.get('from_iata') or '').upper().strip()
        to = (f.get('to_iata') or '').upper().strip()
        if fr and fr not in routing: routing.append(fr)
        if to and to not in routing: routing.append(to)
    # Fallback bei Office/Training: Location als Routing
    if not routing and cas_day.get('location'):
        routing = [(cas_day['location'] or '').upper()]

    layover_ort = (cas_day.get('layover_ort') or '').upper()

    # Confidence: CAS-string-enum → DP-float
    cas_conf = (cas_day.get('confidence') or 'medium').lower()
    confidence_float = {'high': 1.0, 'medium': 0.7, 'low': 0.4}.get(cas_conf, 0.7)

    # has_fl ist für CAS heuristisch — nur ein FL-Marker nach Layover
    # (echte Tour-Layover-Tage). Im DP-Reader war das ein explizites Feld.
    # Setze hier konservativ False — _enrich_dp_with_v8_fields ergänzt prev/next-Kontext.
    has_fl = False

    return {
        'datum':                 cas_day.get('date'),
        'activity_type':         dp_at,
        'raw_marker':            str(cas_day.get('marker', ''))[:30],
        'markers':               [str(cas_day.get('marker', ''))[:14]] if cas_day.get('marker') else [],
        'routing':               routing,
        'has_flight':            dp_at in ('tour', 'same_day'),
        'has_fl':                has_fl,
        'layover_ort':           layover_ort,
        'layover_inland':        _is_inland_code(layover_ort) if layover_ort else None,
        'overnight_after_day':   overnight,
        'homebase_heimkehr':     bool(flights) and not overnight,
        'tour_id':               '',
        'tour_open':             overnight,
        'confidence':            confidence_float,
        'notes':                 '',
        # v11-spezifische CAS-Felder (zusätzlich, brechen DP-Enrichment nicht)
        'start_time':            cas_day.get('start_time', ''),
        'end_time':              cas_day.get('end_time', ''),
        'duration_minutes':      int(cas_day.get('duration_minutes', 0) or 0),
        '_cas_v11':              True,
        '_cas_source_file_id':   cas_day.get('source_file_id', ''),
        '_cas_source_filename':  cas_day.get('source_filename', ''),
        '_cas_activity_orig':    cas_at,
    }


def _match_cas_se_per_day(cas_days, se_structured, homebase='FRA', year=2025):
    """v11: Matcht CAS-Tage + SE-Zeilen pro Kalendertag.

    Wandelt CAS-Output in DP-kompatibles structured_days-Format und ruft
    _match_dp_se_per_day. Das bewährte Match+Klassifikations-Pipeline läuft
    unverändert weiter — nur die primäre Daten-Quelle ist nun CAS.

    Liefert: matched_days-Liste (gleiche Shape wie _match_dp_se_per_day).
    """
    if not cas_days:
        return []
    dp_format_days = []
    skipped = 0
    for cas_d in cas_days:
        dp_d = _cas_day_to_dp_format(cas_d, year, homebase)
        if dp_d and dp_d.get('datum'):
            dp_format_days.append(dp_d)
        else:
            skipped += 1
    if skipped:
        print(f"[v11-cas-match] {skipped} CAS-Tage übersprungen (kein gültiges Datum)")
    structured_days = {'days': dp_format_days}
    return _match_dp_se_per_day(structured_days, se_structured, homebase)


def _snapshot_strip_binaries(obj, depth=0):
    """Entfernt rekursiv PDF-Bytes/base64/raw-File-Daten aus Snapshots.
    Schutz gegen versehentliche PII-/Binary-Persistierung."""
    if depth > 12:  # max recursion
        return '<truncated:max_depth>'
    if isinstance(obj, bytes):
        return f'<bytes:{len(obj)}>'
    if isinstance(obj, str):
        # Heuristik: sehr langer String mit base64-Pattern
        if len(obj) > 2000 and obj.count('/') + obj.count('+') > 50:
            return f'<base64-like:{len(obj)} chars>'
        return obj[:8000] if len(obj) > 8000 else obj
    if isinstance(obj, dict):
        out = {}
        for k, v in obj.items():
            # Verbotene Keys gleich rausfiltern
            if isinstance(k, str) and k.lower() in (
                    'pdf_bytes', 'raw_pdf', 'pdf_b64', 'base64', 'b64',
                    'pdf_content', 'image_bytes', 'file_bytes', 'data_uri'):
                out[k] = '<stripped>'
                continue
            out[k] = _snapshot_strip_binaries(v, depth + 1)
        return out
    if isinstance(obj, (list, tuple)):
        return [_snapshot_strip_binaries(x, depth + 1) for x in obj[:500]]
    return obj


def _save_pipeline_snapshot(job_id, stage_name, data, error=None):
    """v11 P0: speichert Pipeline-Zwischenstand für Offline-Debugging.
    Aktiv nur wenn AEROTAX_CAPTURE_SNAPSHOTS=1.
    Speichert in jobs.data.debug_snapshots — keine PDFs/base64.
    Wird AUCH bei Exception aufgerufen damit Crash-Daten sichtbar sind.
    """
    if not AEROTAX_CAPTURE_SNAPSHOTS:
        return
    if not job_id:
        return
    try:
        clean = _snapshot_strip_binaries(data)
        entry = {
            'stage': stage_name,
            'ts': datetime.utcnow().isoformat() + 'Z',
            'data': clean,
        }
        if error:
            import traceback as _tb
            entry['error'] = {
                'type': type(error).__name__,
                'message': str(error)[:500],
                'trace': _tb.format_exc()[:2000],
            }
        with _jobs_lock:
            j = _jobs.get(job_id)
            if j is None:
                j = _load_job_from_disk(job_id) or {}
                _jobs[job_id] = j
            snaps = j.setdefault('debug_snapshots', [])
            snaps.append(entry)
            # Cap auf 20 Snapshots damit Job-Dict nicht explodiert
            if len(snaps) > 20:
                j['debug_snapshots'] = snaps[-20:]
        try:
            _save_job_to_disk(job_id)
        except Exception as _e:
            print(f"[snapshot] save fail {job_id[:8]}/{stage_name}: {_e}")
        print(f"[snapshot] saved {stage_name} for {job_id[:8]} (error={bool(error)})")
    except Exception as _outer:
        print(f"[snapshot] capture failed {stage_name}: {_outer}")


# ════════════════════════════════════════════════════════════════════════════
# v11 P0 Safety — Schema-Validator für Pipeline-Datenfluss
# Verhindert dass tuple/list/None/str unbemerkt in dict-erwartende Funktionen
# einfließt (Bug a6e291f2: 'tuple' object has no attribute 'get').
# ════════════════════════════════════════════════════════════════════════════
class _PipelineSchemaError(ValueError):
    """Schema-Validierungsfehler im Pipeline-Datenfluss."""
    pass


def _validate_pipeline_shape(obj, expected, path='root'):
    """Rekursive Typ-Prüfung mit Pfad-Tracking. Kein silent-pass.

    expected:
      - 'dict' / 'list' / 'str' / 'int' / 'float' / 'bool' / 'number' / None
      - {'type': 'list', 'item': <expected>}  → jeden Eintrag prüfen
      - {'type': 'dict', 'fields': {key: <expected>, ...}, 'optional': [keys...]}
      - {'type': 'one_of', 'any_of': [<expected>, ...]}
      - None → kein Check (Wildcard)
    """
    if expected is None:
        return
    if isinstance(expected, str):
        type_map = {
            'dict': dict, 'list': list, 'str': str, 'int': int,
            'float': float, 'bool': bool, 'number': (int, float),
        }
        py_type = type_map.get(expected)
        if py_type is None:
            raise _PipelineSchemaError(f'{path}: unbekannter expected-Type "{expected}"')
        if not isinstance(obj, py_type):
            raise _PipelineSchemaError(
                f'{path}: erwarte {expected}, ist {type(obj).__name__} '
                f'(value={repr(obj)[:120]})')
        return
    if not isinstance(expected, dict):
        raise _PipelineSchemaError(f'{path}: malformed expected-Schema')
    etype = expected.get('type')
    if etype == 'one_of':
        for option in expected.get('any_of', []):
            try:
                _validate_pipeline_shape(obj, option, path)
                return
            except _PipelineSchemaError:
                continue
        raise _PipelineSchemaError(f'{path}: keiner der erlaubten Typen passt')
    if etype == 'list':
        if not isinstance(obj, list):
            raise _PipelineSchemaError(
                f'{path}: erwarte list, ist {type(obj).__name__}')
        item_schema = expected.get('item')
        if item_schema is not None:
            for i, x in enumerate(obj):
                _validate_pipeline_shape(x, item_schema, f'{path}[{i}]')
        return
    if etype == 'dict':
        if not isinstance(obj, dict):
            raise _PipelineSchemaError(
                f'{path}: erwarte dict, ist {type(obj).__name__} '
                f'(value={repr(obj)[:120]})')
        fields = expected.get('fields') or {}
        optional = set(expected.get('optional') or [])
        for fname, fschema in fields.items():
            if fname in obj:
                _validate_pipeline_shape(obj[fname], fschema, f'{path}.{fname}')
            elif fname not in optional:
                raise _PipelineSchemaError(
                    f'{path}.{fname}: Pflichtfeld fehlt')
        return
    raise _PipelineSchemaError(f'{path}: unbekannter etype "{etype}"')


